CREATE INDEX IF NOT EXISTS idx_sg_program  ON public.style_groups (program);

-- Facet options for the customer / program filter combos (group-level counts).
CREATE OR REPLACE FUNCTION public.get_path_facets(p_customer text DEFAULT NULL)
RETURNS jsonb
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path TO 'public'
AS $$
  SELECT jsonb_build_object(
    'customers', COALESCE((
      SELECT jsonb_agg(jsonb_build_object('name', customer, 'count', cnt) ORDER BY customer)
      FROM (
        SELECT customer, count(*) AS cnt
        FROM style_groups
        WHERE customer IS NOT NULL
        GROUP BY customer
      ) c
    ), '[]'::jsonb),
    'programs', COALESCE((
      SELECT jsonb_agg(jsonb_build_object('name', program, 'count', cnt) ORDER BY program)
      FROM (
        SELECT program, count(*) AS cnt
        FROM style_groups
        WHERE program IS NOT NULL
          AND (p_customer IS NULL OR customer = p_customer)
        GROUP BY program
      ) p
    ), '[]'::jsonb)
  );
$$;

GRANT EXECUTE ON FUNCTION public.get_path_facets(text) TO anon, authenticated;
GRANT EXECUTE ON FUNCTION public.infer_path_attrs(text) TO anon, authenticated;

SET statement_timeout = '180s';
UPDATE public.assets a
SET stage = j->>'stage', customer = j->>'customer', program = j->>'program'
FROM (SELECT id, public.infer_path_attrs(relative_path) AS j FROM public.assets
      WHERE relative_path LIKE 'Decor/Character Licensed/____New Structure/In Development/%') src
WHERE a.id = src.id;

SET statement_timeout = '180s';
UPDATE public.style_groups g
SET stage = j->>'stage', customer = j->>'customer', program = j->>'program'
FROM (SELECT id, public.infer_path_attrs(folder_path) AS j FROM public.style_groups) src
WHERE g.id = src.id;

SET statement_timeout = '180s';
UPDATE public.assets a
SET stage = j->>'stage', customer = j->>'customer', program = j->>'program'
FROM (SELECT id, public.infer_path_attrs(relative_path) AS j FROM public.assets
      WHERE relative_path LIKE 'Decor/Character Licensed/____New Structure/Concept Approved Designs/%') src
WHERE a.id = src.id;

SET statement_timeout = '180s';
WITH batch AS (
  SELECT id FROM public.assets
  WHERE relative_path LIKE 'Decor/Character Licensed/____New Structure/Concept Approved Designs/%'
    AND stage IS NULL
  LIMIT 20000
)
UPDATE public.assets a
SET stage = public.infer_path_attrs(a.relative_path)->>'stage'
FROM batch WHERE a.id = batch.id;
SELECT count(*) AS remaining FROM public.assets
WHERE relative_path LIKE 'Decor/Character Licensed/____New Structure/Concept Approved Designs/%' AND stage IS NULL;

