1	-- Path-derived attributes: stage / customer / program inferred from the NAS folder layout.
2	-- Anchor folder: "____New Structure" under Decor/Character Licensed.
3	--   stage   = the folder directly under "____New Structure" (set for ALL files there)
4	--   customer/program = only reliable in the "In Development / Customer Adopted" branch (v1 scope)
5	-- (Backfill of existing rows was run separately after this DDL via batched UPDATEs; new
6	--  rows are populated by the triggers below.)
7	
8	ALTER TABLE public.assets
9	  ADD COLUMN IF NOT EXISTS stage text,
10	  ADD COLUMN IF NOT EXISTS customer text,
11	  ADD COLUMN IF NOT EXISTS program text;
12	
13	ALTER TABLE public.style_groups
14	  ADD COLUMN IF NOT EXISTS stage text,
15	  ADD COLUMN IF NOT EXISTS customer text,
16	  ADD COLUMN IF NOT EXISTS program text;
17	
18	CREATE OR REPLACE FUNCTION public.infer_path_attrs(p_path text)
19	RETURNS jsonb
20	LANGUAGE plpgsql
21	IMMUTABLE
22	AS $$
23	DECLARE
24	  segs text[];
25	  idx  int;
26	  s    text;
27	  c1   text;
28	  cust text := NULL;
29	  prog text := NULL;
30	BEGIN
31	  IF p_path IS NULL OR p_path = '' THEN
32	    RETURN jsonb_build_object('stage', NULL, 'customer', NULL, 'program', NULL);
33	  END IF;
34	
35	  segs := string_to_array(p_path, '/');
36	  idx  := array_position(segs, '____New Structure');
37	  IF idx IS NULL THEN
38	    RETURN jsonb_build_object('stage', NULL, 'customer', NULL, 'program', NULL);
39	  END IF;
40	
41	  s := NULLIF(segs[idx + 1], '');
42	  IF s IS NULL THEN
43	    RETURN jsonb_build_object('stage', NULL, 'customer', NULL, 'program', NULL);
44	  END IF;
45	
46	  -- Customer / program are only reliably encoded in the "In Development / Customer Adopted" branch.
47	  IF s = 'In Development' AND segs[idx + 2] = 'Customer Adopted' THEN
48	    c1 := NULLIF(segs[idx + 3], '');
49	    IF c1 IS NULL THEN
50	      cust := NULL; prog := NULL;
51	    ELSIF c1 = '_FINISHED' THEN
52	      -- wrapper bucket: _FINISHED / <Customer>_finished / <Program> / <SKU>
53	      cust := NULLIF(regexp_replace(COALESCE(segs[idx + 4], ''), '_finished$', '', 'i'), '');
54	      prog := NULLIF(segs[idx + 5], '');
55	    ELSIF left(c1, 1) = '_' THEN
56	      -- status buckets (_NOT APPROVED, _REJECTED, _No Customer, _NOT SUBMITTED): no real customer
57	      cust := NULL; prog := NULL;
58	    ELSE
59	      cust := c1;
60	      prog := NULLIF(segs[idx + 4], '');
61	    END IF;
62	
63	    -- Guard: the program slot must be a real program folder, not the SKU folder or a file.
64	    IF prog IS NOT NULL THEN
65	      IF prog ~ '\.[A-Za-z0-9]+$' THEN
66	        prog := NULL;  -- looks like a filename
67	      ELSIF prog !~ '[[:space:]]' AND prog ~ '^[A-Za-z]{1,6}[0-9][A-Za-z0-9]*$' AND length(prog) >= 8 THEN
68	        prog := NULL;  -- looks like a SKU code (no program folder present)
69	      END IF;
70	    END IF;
71	  END IF;
72	
73	  RETURN jsonb_build_object('stage', s, 'customer', cust, 'program', prog);
74	END;
75	$$;
76	
77	CREATE OR REPLACE FUNCTION public.trg_set_asset_path_attrs()
78	RETURNS trigger
79	LANGUAGE plpgsql
80	AS $$
81	DECLARE j jsonb;
82	BEGIN
83	  j := public.infer_path_attrs(NEW.relative_path);
84	  NEW.stage    := j ->> 'stage';
85	  NEW.customer := j ->> 'customer';
86	  NEW.program  := j ->> 'program';
87	  RETURN NEW;
88	END;
89	$$;
90	
91	CREATE OR REPLACE FUNCTION public.trg_set_sg_path_attrs()
92	RETURNS trigger
93	LANGUAGE plpgsql
94	AS $$
95	DECLARE j jsonb;
96	BEGIN
97	  j := public.infer_path_attrs(NEW.folder_path);
98	  NEW.stage    := j ->> 'stage';
99	  NEW.customer := j ->> 'customer';
100	  NEW.program  := j ->> 'program';
101	  RETURN NEW;
102	END;
103	$$;
104	
105	DROP TRIGGER IF EXISTS trg_set_path_attrs ON public.assets;
106	CREATE TRIGGER trg_set_path_attrs
107	  BEFORE INSERT OR UPDATE OF relative_path ON public.assets
108	  FOR EACH ROW EXECUTE FUNCTION public.trg_set_asset_path_attrs();
109	
110	DROP TRIGGER IF EXISTS trg_set_path_attrs ON public.style_groups;
111	CREATE TRIGGER trg_set_path_attrs
112	  BEFORE INSERT OR UPDATE OF folder_path ON public.style_groups
113	  FOR EACH ROW EXECUTE FUNCTION public.trg_set_sg_path_attrs();
114	
115	CREATE INDEX IF NOT EXISTS idx_assets_stage    ON public.assets (stage);
116	CREATE INDEX IF NOT EXISTS idx_assets_customer ON public.assets (customer);
117	CREATE INDEX IF NOT EXISTS idx_assets_program  ON public.assets (program);
118	CREATE INDEX IF NOT EXISTS idx_assets_program_trgm  ON public.assets USING gin (program gin_trgm_ops);
119	CREATE INDEX IF NOT EXISTS idx_assets_customer_trgm ON public.assets USING gin (customer gin_trgm_ops);
120	
121	CREATE INDEX IF NOT EXISTS idx_sg_stage    ON public.style_groups (stage);
122	CREATE INDEX IF NOT EXISTS idx_sg_customer ON public.style_groups (customer);
123	CREATE INDEX IF NOT EXISTS idx_sg_program  ON public.style_groups (program);
124	
125	-- Facet options for the customer / program filter combos (group-level counts).
126	CREATE OR REPLACE FUNCTION public.get_path_facets(p_customer text DEFAULT NULL)
127	RETURNS jsonb
128	LANGUAGE sql
129	STABLE
130	SECURITY DEFINER
131	SET search_path TO 'public'
132	AS $$
133	  SELECT jsonb_build_object(
134	    'customers', COALESCE((
135	      SELECT jsonb_agg(jsonb_build_object('name', customer, 'count', cnt) ORDER BY customer)
136	      FROM (
137	        SELECT customer, count(*) AS cnt
138	        FROM style_groups
139	        WHERE customer IS NOT NULL
140	        GROUP BY customer
141	      ) c
142	    ), '[]'::jsonb),
143	    'programs', COALESCE((
144	      SELECT jsonb_agg(jsonb_build_object('name', program, 'count', cnt) ORDER BY program)
145	      FROM (
146	        SELECT program, count(*) AS cnt
147	        FROM style_groups
148	        WHERE program IS NOT NULL
149	          AND (p_customer IS NULL OR customer = p_customer)
150	        GROUP BY program
151	      ) p
152	    ), '[]'::jsonb)
153	  );
154	$$;
155	
156	GRANT EXECUTE ON FUNCTION public.get_path_facets(text) TO anon, authenticated;
157	GRANT EXECUTE ON FUNCTION public.infer_path_attrs(text) TO anon, authenticated;
158

